module mux8to1 (
    input [7:0] input_data,  // 8 input_data inputs
    input [2:0] sel,   // 3-bit select input
    output reg y       // output
);
    always @(*) begin
        case (sel)
            3'b000: y = input_data[0];
            3'b001: y = input_data[1];
            3'b010: y = input_data[2];
            3'b011: y = input_data[3];
            3'b100: y = input_data[4];
            3'b101: y = input_data[5];
            3'b110: y = input_data[6];
            3'b111: y = input_data[7];
            default: y = 1'b0; // default case
        endcase
    end
endmodule
